INSERT INTO `popular_videos` (`id`, `bvid`, `aid`, `title`, `description`, `author`, `tname`, `cover_url`, `publish_date`, `duration`, `view_count`, `danmaku_count`, `reply_count`, `comment_count`, `favorite_count`, `coin_count`, `share_count`, `like_count`, `score`, `rcmd_reason`, `scraped_at`) VALUES (2468, 'BV175XeBxEVX', 116317562604266, '雪山上到底都有啥啊！', '事情是这样的：	3月30日凌晨，苏州市斜塘河地下20余米深处，中铁十四局承建的通甬高铁苏州东隧道 “通甬园梦号” 盾构机掘进总里程突破 10000 米，为这条 “中国城市高铁第一隧” 全线贯通打下坚实基础。\n	苏州东隧道是通甬高铁控制性工程，跨越苏州吴中区和苏州工业园，全长15.57公里，单洞双线，最大埋深达58米，是我国建设标准最高、里程最长的时速350公里城市高铁隧道，被誉为“中国城市高铁第一隧”。	隧道采用明挖法和盾构法施工，其盾构段长约11.5公里，采用开挖直径达14.82米的“通甬园梦号”盾构机', '中铁十四局', NULL, 'http://i0.hdslb.com/bfs/archive/15702c72ec9a5c029e67378db547607d8b634052.jpg', '2026-03-30 18:11:04', 41, 391442, 643, 0, 622, 2933, 537, 867, 53381, 0, NULL, '2026-04-02 19:09:33');
