INSERT INTO `popular_videos` (`id`, `bvid`, `aid`, `title`, `description`, `author`, `tname`, `cover_url`, `publish_date`, `duration`, `view_count`, `danmaku_count`, `reply_count`, `comment_count`, `favorite_count`, `coin_count`, `share_count`, `like_count`, `score`, `rcmd_reason`, `scraped_at`) VALUES (2463, 'BV1ck9VB6EMp', 116326672702345, '警惕！日本彻底撕下伪装', '3月31日，日本防卫省宣布在陆上自卫队熊本县健军驻屯地和静冈县富士驻屯地部署长射程导弹。总台记者在静冈县看到，一些民众今天冒雨自发聚集在自卫队外进行抗议。日本的这次部署，绝对不是单纯的装备升级，而是标志着日本战后“专守防卫”原则的实质突破。当射程可达1000公里、能够执行所谓“对敌基地攻击能力”的导弹走向实战部署，日本安全政策的边界，已经被践踏无遗。有日本民众质问，那些宣称“把导弹部署在富士驻屯地是好事”的人，是要把日本变成“导弹列岛”吗？', '央视新闻', NULL, 'http://i0.hdslb.com/bfs/archive/b876ebfcd6a53f0032c43361526b51673c1029bf.jpg', '2026-04-01 08:45:36', 239, 1025662, 2093, 0, 8430, 7860, 6232, 7591, 92527, 0, NULL, '2026-04-02 19:09:33');
