INSERT INTO `popular_videos` (`id`, `bvid`, `aid`, `title`, `description`, `author`, `tname`, `cover_url`, `publish_date`, `duration`, `view_count`, `danmaku_count`, `reply_count`, `comment_count`, `favorite_count`, `coin_count`, `share_count`, `like_count`, `score`, `rcmd_reason`, `scraped_at`) VALUES (2457, 'BV17q9EBEEJj', 116329893862729, 'ChiliChill「辞职信」广州Live版', '她在这座城市努力了好几年，做着一份还不错工作，每天地铁上下班，那地铁里的“人味”——混杂着不同香水的芬芳、地下潮湿的霉意、隐隐的汗渍，还有匆忙脚步搅起的尘埃味——她记忆特别深刻，甚至觉得这个味道挺好闻的，有一种拼搏的生猛感在里面，让她觉得自己真实地活着，在打拼；\n\n偶尔加班到深夜虽然累，但某个阶段似乎觉得挺好，自己也像小说里、社交媒体上写的那些打拼自己人生的人那样，开始加班了，那种微妙的感觉，仿佛生活正按某种期待的剧本推进；\n\n可日子渐渐还是生出异样，活得不像自己的心情与日俱增。周末本想去公园散步，但居然', 'YuH_ChiliChill', NULL, 'http://i2.hdslb.com/bfs/archive/8f60875b61809902f9f44df19fdb722f9b10d7d2.jpg', '2026-04-01 22:24:10', 207, 63789, 177, 0, 1044, 3780, 6743, 2769, 7660, 0, NULL, '2026-04-02 19:09:33');
