INSERT INTO `video_comment` (`comment_id`, `bvid`, `task_id`, `username`, `gender`, `text_type`, `content`, `normalized_content`, `sentiment_score`, `sentiment_confidence`, `sentiment_intensity`, `sentiment_source`, `sentiment_version`, `emotion_tags_json`, `aspect_details_json`, `sentiment_label`, `like_count`, `reply_count`, `aspect`, `publish_time`, `scraped_at`) VALUES (293970572961, 'BV1YFAMzKEAh', '84c86834-b4e7-4283-901c-1de113747016', '我相信明天会更好l', '保密', 'comment', '现在只能鼓起勇气坦漏身份向好心人求助，我曾是人民子  弟.兵，\n驻守   边  疆无惧危险，守护万家灯火\n可我抱着我那才6岁的孩子，我一次次在医院流泪，他才6岁大啊，被确诊为重病，从这天起，我们就踏上了漫长的求医路，我们日夜守护只盼孩子能慢慢好起来，可命运没有眷顾我们，病情急剧恶化，小小的身板要承受住一次一次的穿刺和化疗，那么细的针.扎在他的身体上。他疼的止不住的颤抖，孩子麻醉刚醒后趴我耳朵上跟我说，爸爸。我太疼了，我想回家，我不想治了，这几个字深深的刺痛了我的心，可如今我的退伍费早已经耗尽，面对这后面昂贵的医疗费，我真的扛不住了，我承认我无能，可我真不能放弃，请帮帮我这个绝境中的家庭吧，我甄建东一定一定会记住各位的恩情，给各位深鞠躬感恩了，好人一辈子平安！！！', '现在只能鼓起勇气坦漏身份向好心人求助，我曾是人民子 弟.兵， 驻守 边 疆无惧危险，守护万家灯火 可我抱着我那才6岁的孩子，我一次次在医院流泪，他才6岁大啊，被确诊为重病，从这天起，我们就踏上了漫长的求医路，我们日夜守护只盼孩子能慢慢好起来，可命运没有眷顾我们，病情急剧恶化，小小的身板要承受住一次一次的穿刺和化疗，那么细的针.扎在他的身体上。他疼的止不住的颤抖，孩子麻醉刚醒后趴我耳朵上跟我说，爸爸。我太疼了，我想回家，我不想治了，这几个字深深的刺痛了我的心，可如今我的退伍费早已经耗尽，面对这后面昂贵的医疗费，我真的扛不住了，我承认我无能，可我真不能放弃，请帮帮我这个绝境中的家庭吧，我甄建东一定一定会记住各位的恩情，给各位深鞠躬感恩了，好人一辈子平安！！', 0.9036, 0.9352, 'STRONG', 'transformer_comment_v1', 'comment-multilingual-distilbert-v1.0.0', '[]', '[{\"label\": \"NEGATIVE\", \"score\": -0.4541, \"aspect\": \"性能\", \"source\": \"transformer_comment_v1\", \"context\": \"我们日夜守护只盼孩子能慢慢好起来\", \"version\": \"comment-multilingual-distilbert-v1.0.0\", \"confidence\": 0.5927}, {\"label\": \"POSITIVE\", \"score\": 0.0848, \"aspect\": \"价格\", \"source\": \"transformer_comment_v1\", \"context\": \"面对这后面昂贵的医疗费\", \"version\": \"comment-multilingual-distilbert-v1.0.0\", \"confidence\": 0.4679}]', 'POSITIVE', 0, 0, '性能', '2026-03-23 23:49:12', '2026-03-24 13:49:28');
