INSERT INTO `video_comment` (`comment_id`, `bvid`, `task_id`, `username`, `gender`, `text_type`, `content`, `normalized_content`, `sentiment_score`, `sentiment_confidence`, `sentiment_intensity`, `sentiment_source`, `sentiment_version`, `emotion_tags_json`, `aspect_details_json`, `sentiment_label`, `like_count`, `reply_count`, `aspect`, `publish_time`, `scraped_at`) VALUES (293974028929, 'BV1YFAMzKEAh', '84c86834-b4e7-4283-901c-1de113747016', '幽夜炎', '保密', 'comment', '泡椒凤爪那个，你买那些的鸡爪，它就是偏白色的呀。过氧化氢也是比较常见的食品添加助剂，在工艺没更新之前，经常用作鸡爪的加工。后来国标更新之后就不用过氧化氢了，不过还是有很多的保色剂的，有的比过氧化氢还便宜。过氧化氢的问题是明明有更便宜的保色剂，为什么要用漂白性强的过氧化氢，这从侧面说明了最大的问题是他有可能用的鸡爪质量不好，导致需要高强度漂白跟过氧化氢本身没什么关系，而且学过初中化学的都知道过氧化氢自行分解后的产物就是水和氧气。', '泡椒凤爪那个，你买那些的鸡爪，它就是偏白色的呀。过氧化氢也是比较常见的食品添加助剂，在工艺没更新之前，经常用作鸡爪的加工。后来国标更新之后就不用过氧化氢了，不过还是有很多的保色剂的，有的比过氧化氢还便宜。过氧化氢的问题是明明有更便宜的保色剂，为什么要用漂白性强的过氧化氢，这从侧面说明了最大的问题是他有可能用的鸡爪质量不好，导致需要高强度漂白跟过氧化氢本身没什么关系，而且学过初中化学的都知道过氧化氢自行分解后的产物就是水和氧气。', 0.3718, 0.5122, 'WEAK', 'transformer_comment_v1', 'comment-multilingual-distilbert-v1.0.0', '[\"praise\"]', '[{\"label\": \"NEGATIVE\", \"score\": -0.4972, \"aspect\": \"价格\", \"source\": \"transformer_comment_v1\", \"context\": \"有的比过氧化氢还便宜；过氧化氢的问题是明明有更便宜的保色剂\", \"version\": \"comment-multilingual-distilbert-v1.0.0\", \"confidence\": 0.6501}, {\"label\": \"NEUTRAL\", \"score\": -0.0283, \"aspect\": \"系统\", \"source\": \"transformer_comment_v1\", \"context\": \"在工艺没更新之前；后来国标更新之后就不用过氧化氢了\", \"version\": \"comment-multilingual-distilbert-v1.0.0\", \"confidence\": 0.3713}, {\"label\": \"NEGATIVE\", \"score\": -0.5125, \"aspect\": \"食材\", \"source\": \"transformer_comment_v1\", \"context\": \"过氧化氢也是比较常见的食品添加助剂\", \"version\": \"comment-multilingual-distilbert-v1.0.0\", \"confidence\": 0.6246}]', 'POSITIVE', 1, 0, '价格', '2026-03-24 00:34:05', '2026-03-24 13:49:28');
