INSERT INTO `video_comment` (`comment_id`, `bvid`, `task_id`, `username`, `gender`, `text_type`, `content`, `normalized_content`, `sentiment_score`, `sentiment_confidence`, `sentiment_intensity`, `sentiment_source`, `sentiment_version`, `emotion_tags_json`, `aspect_details_json`, `sentiment_label`, `like_count`, `reply_count`, `aspect`, `publish_time`, `scraped_at`) VALUES (294008046673, 'BV1YFAMzKEAh', '84c86834-b4e7-4283-901c-1de113747016', '愿-切顺利吧', '保密', 'comment', '抱歉打扰大家了[抱拳]我曾经的军旅生涯让我成为了人民子弟兵，曾经驻守边疆，面对危险无所畏惧，守护过万家灯火。然而，如今我抱着我那5岁的儿子，他身患重症，我一次次在医院流泪。从那天开始，我们走上了漫长而艰辛的求医之路。我们日夜守护，只希望孩子能够逐渐康复。但是命运并未眷顾我们，病情急剧恶化，她不得不承受穿刺和化疗的痛苦。\n每次看到他被针扎得身体颤抖，我的心如刀割。她麻醉刚醒后，趴在我耳朵上说出的话让我心痛不已，他说：“爸爸，我太疼了，我想回家，我不想治了。”听到这些，我无能为力，但我不能放弃。我的退伍费已经用完，面对后续高昂的医疗费，我深感压力巨大。希望大家能帮帮孩子，铭记各位的恩情，感谢你们的帮助。请帮助我这个处于绝境中的家庭，我会永远记住你们的善举，并祝福好人一生平安快乐！！！', '抱歉打扰大家了[抱拳]我曾经的军旅生涯让我成为了人民子弟兵，曾经驻守边疆，面对危险无所畏惧，守护过万家灯火。然而，如今我抱着我那5岁的儿子，他身患重症，我一次次在医院流泪。从那天开始，我们走上了漫长而艰辛的求医之路。我们日夜守护，只希望孩子能够逐渐康复。但是命运并未眷顾我们，病情急剧恶化，她不得不承受穿刺和化疗的痛苦。 每次看到他被针扎得身体颤抖，我的心如刀割。她麻醉刚醒后，趴在我耳朵上说出的话让我心痛不已，他说：“爸爸，我太疼了，我想回家，我不想治了。”听到这些，我无能为力，但我不能放弃。我的退伍费已经用完，面对后续高昂的医疗费，我深感压力巨大。希望大家能帮帮孩子，铭记各位的恩情，感谢你们的帮助。请帮助我这个处于绝境中的家庭，我会永远记住你们的善举，并祝福好人一生平安快乐！！', 0.9369, 0.9495, 'STRONG', 'transformer_comment_v1', 'comment-multilingual-distilbert-v1.0.0', '[]', '[{\"label\": \"NEGATIVE\", \"score\": -0.9459, \"aspect\": \"性能\", \"source\": \"transformer_comment_v1\", \"context\": \"并祝福好人一生平安快乐\", \"version\": \"comment-multilingual-distilbert-v1.0.0\", \"confidence\": 0.9556}, {\"label\": \"POSITIVE\", \"score\": 0.5107, \"aspect\": \"口味\", \"source\": \"transformer_comment_v1\", \"context\": \"她不得不承受穿刺和化疗的痛苦\", \"version\": \"comment-multilingual-distilbert-v1.0.0\", \"confidence\": 0.6558}]', 'POSITIVE', 0, 0, '性能', '2026-03-24 13:10:36', '2026-03-24 13:49:28');
