INSERT INTO `video_comment` (`comment_id`, `bvid`, `task_id`, `username`, `gender`, `text_type`, `content`, `normalized_content`, `sentiment_score`, `sentiment_confidence`, `sentiment_intensity`, `sentiment_source`, `sentiment_version`, `emotion_tags_json`, `aspect_details_json`, `sentiment_label`, `like_count`, `reply_count`, `aspect`, `publish_time`, `scraped_at`) VALUES (296433762624, 'BV1YFAMzKEAh', '84c86834-b4e7-4283-901c-1de113747016', '期盼您来看看孩子', '保密', 'comment', '对不起，实在没办法了，只能厚着脸皮在这里求大家帮帮忙。孩子查出了急性白血病，这么小的年纪，本该开开心心的，现在却要天天面对化疗、穿刺，每次疼得缩成一团，我这个当妈妈的，心都像被刀割一样，恨不得所有罪都让我来受。为了给他治病，家里所有积蓄早就花光了，能卖的东西全都卖了，亲戚朋友能借的也都借遍了，现在已经欠了一身债。可后续治疗还要花很多钱，这点钱根本不够，看着每天不断增加的费用，我们真的快撑不下去了。但我们从来没想过放弃，孩子还那么小，他还想活下去，这也是我们唯一的支撑。今天实在走投无路，才鼓起勇气向大家求助。希望各位好心人能伸手帮我们一把，哪怕只是一点点，对我们来说都是活下去的希望。这份恩情，我们一家人一辈子都不会忘记，谢谢大家。', '对不起，实在没办法了，只能厚着脸皮在这里求大家帮帮忙。孩子查出了急性白血病，这么小的年纪，本该开开心心的，现在却要天天面对化疗、穿刺，每次疼得缩成一团，我这个当妈妈的，心都像被刀割一样，恨不得所有罪都让我来受。为了给他治病，家里所有积蓄早就花光了，能卖的东西全都卖了，亲戚朋友能借的也都借遍了，现在已经欠了一身债。可后续治疗还要花很多钱，这点钱根本不够，看着每天不断增加的费用，我们真的快撑不下去了。但我们从来没想过放弃，孩子还那么小，他还想活下去，这也是我们唯一的支撑。今天实在走投无路，才鼓起勇气向大家求助。希望各位好心人能伸手帮我们一把，哪怕只是一点点，对我们来说都是活下去的希望。这份恩情，我们一家人一辈子都不会忘记，谢谢大家。', 0.7294, 0.8181, 'MEDIUM', 'transformer_comment_v1', 'comment-multilingual-distilbert-v1.0.0', '[]', '[{\"label\": \"POSITIVE\", \"score\": 0.4708, \"aspect\": \"性能\", \"source\": \"transformer_comment_v1\", \"context\": \"我们真的快撑不下去了\", \"version\": \"comment-multilingual-distilbert-v1.0.0\", \"confidence\": 0.6311}, {\"label\": \"POSITIVE\", \"score\": 0.4792, \"aspect\": \"价格\", \"source\": \"transformer_comment_v1\", \"context\": \"可后续治疗还要花很多钱；这点钱根本不够\", \"version\": \"comment-multilingual-distilbert-v1.0.0\", \"confidence\": 0.6177}]', 'POSITIVE', 1, 0, '性能', '2026-03-23 18:32:23', '2026-03-24 13:49:28');
