INSERT INTO `video_comment` (`comment_id`, `bvid`, `task_id`, `username`, `gender`, `text_type`, `content`, `normalized_content`, `sentiment_score`, `sentiment_confidence`, `sentiment_intensity`, `sentiment_source`, `sentiment_version`, `emotion_tags_json`, `aspect_details_json`, `sentiment_label`, `like_count`, `reply_count`, `aspect`, `publish_time`, `scraped_at`) VALUES (296513719344, 'BV1NHQQBDE82', '1f993295-bfc5-4960-8e45-1f5ff7a10e01', '佩特莉', '保密', 'comment', '[笑哭]一般般，感觉被坑了。击破效率和拐力都差了一些，输出也比不上正经C。南宫技能组合也怪怪的，明明是C的模板带的也是偏输出的盘子，但又是个辅C，不能驻场输出，伤害也不算高。严重缺重拍点，但是补的又特别慢，强特几乎没联动，没有重拍点切出来除了卡手几乎没什么用，我怀疑南宫是被阉割过的。正常来讲强特应该给个回复重拍点或者开启以太帷幕的效果，实际上只有个联动普攻，并没有其他的效果', '[笑哭]一般般，感觉被坑了。击破效率和拐力都差了一些，输出也比不上正经C。南宫技能组合也怪怪的，明明是C的模板带的也是偏输出的盘子，但又是个辅C，不能驻场输出，伤害也不算高。严重缺重拍点，但是补的又特别慢，强特几乎没联动，没有重拍点切出来除了卡手几乎没什么用，我怀疑南宫是被阉割过的。正常来讲强特应该给个回复重拍点或者开启以太帷幕的效果，实际上只有个联动普攻，并没有其他的效果', 0.8580, 0.8704, 'STRONG', 'transformer_comment_v1', 'comment-multilingual-distilbert-v1.0.0', '[\"praise\", \"amused\"]', '[{\"label\": \"POSITIVE\", \"score\": 0.5116, \"aspect\": \"性能\", \"source\": \"transformer_comment_v1\", \"context\": \"补的又特别慢；没有重拍点切出来除了卡手几乎没什么用\", \"version\": \"comment-multilingual-distilbert-v1.0.0\", \"confidence\": 0.585}]', 'POSITIVE', 1, 0, '性能', '2026-03-24 14:25:24', '2026-03-24 16:54:21');
